from cryptography.fernet import Fernet
from configparser import ConfigParser

# Load the key from config
config = ConfigParser()
config.read('app_config.ini')
key = config.get('encryption', 'key').encode()

# Create a cipher suite
cipher_suite = Fernet(key)

def encrypt_credit_card(card_number):
    card_number_bytes = card_number.encode('utf-8')
    encrypted_card = cipher_suite.encrypt(card_number_bytes)
    return encrypted_card

def decrypt_credit_card(encrypted_card):
    decrypted_card = cipher_suite.decrypt(encrypted_card)
    return decrypted_card.decode('utf-8')